'use strict';

function businessDraft(taskId, variant = 'new') {
  const scope = variant === 'existing'
    ? '这是存量增强：新增自动升级；审批判定和审计规则受影响；组织关系与已有终态保持不变；组织架构维护属于非目标。'
    : variant === 'low-impact'
      ? '这是低影响调整。核验范围为审批结果展示；当前结论是业务概念、规则和责任均沿用；判断依据为现行规范与运行行为一致；沿用理由是本次只修正文案。'
      : '本次新增审批任务自动升级；范围包含逾期判定、升级结果和通知语义，排除组织架构维护。';

  return `---
artifactId: "BD-${taskId}"
version: "1.0.0"
---

# Business Design

## 概述
本文定义审批任务自动升级的业务语义目标态，供产品、业务、方案和测试设计消费；采用已批准 Requirement Baseline，并保持组织关系归属约束。

## 需求基线与业务设计范围
${scope} Requirement Acceptance 要求逾期任务只形成一次可观察升级结果；没有未固化方案偏好或授权后移事项。

## 业务目标态总览
审批任务达到 SLA 截止时间且仍可处理时，由当前责任关系确定升级责任人并形成一次升级结果；重复判定保持同一业务结果，撤回和终态任务不再升级。

## 业务概念、对象与度量语义
审批任务是等待业务决定的对象；SLA 截止时间是任务应被处理的业务时刻；升级是逾期任务责任上移的唯一业务事件；次数按任务与升级级次去重，空责任关系表示暂不可判定。

## 业务参与者、责任与适用范围
申请人观察结果，审批人承担当前处理责任，上级审批人承担升级后的处理责任；规则适用于启用 SLA 的有效审批任务，已撤回、已通过和已拒绝任务排除。

## 业务场景与业务行为
前置条件为任务有效且到达截止时间；触发者为时间事实；关键事实为任务待审批且存在上级；业务行为是应用升级规则；结果为升级成立；申请人和责任人可观察升级状态与时间。

## 业务规则与判定逻辑
待审批任务在截止时间到达后纳入升级；终态和已撤回任务排除；同一任务同一级次只产生一次有效升级；撤回优先于尚未形成的升级；责任关系缺失时结果为暂不可判定并等待业务修正。

## 时间、状态与生命周期语义
以任务所属组织的业务时区判断截止时间。任务可处于待审批、已升级、已通过、已拒绝或已撤回；已通过、已拒绝和已撤回是冻结终态，规则版本变化不重算已冻结结果。

## 异常、边界与业务结果
责任关系缺失时不产生错误责任人并展示暂不可判定；重复事实返回既有升级结果；截止时刻同时撤回时以撤回为最终结果；通知不可见不改变已经成立的业务升级结果。

## 关键业务决策、约束与风险
业务约束是同一任务同一级次结果唯一，终态不可升级。残余风险是组织责任关系延迟修正会延后可判定时间；不在此选择技术实现。

## 业务验收与需求追溯
逾期升级目标落到待审批纳入规则；一次结果承诺落到去重规则；终态保护落到排除和冻结规则；异常验收覆盖责任关系缺失、重复事实和截止时刻撤回。

## 下游设计约束与交接
Solution Design 必须保持任务、截止时间、升级事件和冻结终态的业务含义，实现唯一升级结果、暂不可判定结果和可观察反馈；系统边界、接口、存储和重试机制留待下游决定。

## 词汇表
SLA 截止时间：任务应完成处理的业务时刻。升级：逾期任务责任上移并形成可观察结果的业务事件。

## 参考资料
当前任务 Requirement Baseline、现行审批业务规范、已核验的审批运行行为。
`;
}

module.exports = { businessDraft };
